/* ========================================================
   5. SHOPPING CART LOGIC
   The cart is a simple array of product objects.
   Each item in the array also has a "qty" property added.
======================================================== */

// Start with an empty cart
let cart = [];

/**
 * addToCart — adds a product to the cart by its ID.
 * If the item is already in the cart, just increase its quantity.
 * Then re-renders the cart UI and shows a toast notification.
 *
 * @param {number} productId — the id field from the products array
 */
function addToCart(productId) {
  // Find the product object that matches the ID
  const product = products.find(p => p.id === productId);

  // Check if this product is already in the cart
  const existingItem = cart.find(item => item.id === productId);

  if (existingItem) {
    // Already in cart — just increase quantity
    existingItem.qty += 1;
  } else {
    // New item — add it to the cart array with qty: 1
    // We use spread (...) to copy all product properties
    cart.push({ ...product, qty: 1 });
  }

  // Update the badge number on the cart icon
  updateCartCount();

  // Refresh the cart sidebar HTML
  renderCart();

  // Show a little popup message
  showToast(`${product.name} added to cart!`);
}

/**
 * updateQty — increases or decreases the quantity of a cart item.
 * If quantity drops to 0 or below, the item is removed from the cart.
 *
 * @param {number} productId — id of the item to update
 * @param {number} change    — +1 to increase, -1 to decrease
 */
function updateQty(productId, change) {
  // Find the item in the cart
  const item = cart.find(i => i.id === productId);
  if (!item) return;  // safety check — do nothing if not found

  // Apply the change
  item.qty += change;

  // Remove from cart if quantity reaches zero
  if (item.qty <= 0) {
    cart = cart.filter(i => i.id !== productId);
  }

  // Update UI
  updateCartCount();
  renderCart();
}

/**
 * updateCartCount — recalculates total items in the cart
 * and updates the badge number shown on the cart icon.
 */
function updateCartCount() {
  // Add up all qty values in the cart array
  const totalItems = cart.reduce((sum, item) => sum + item.qty, 0);
  document.getElementById('cartCount').textContent = totalItems;
}

/**
 * renderCart — builds the HTML for the cart sidebar
 * and injects it into the #cartList element.
 * Also updates the total price display.
 */
function renderCart() {
  const cartListEl = document.getElementById('cartList');

  // If cart is empty, show a placeholder message
  if (cart.length === 0) {
    cartListEl.innerHTML = `
      <div style="text-align: center; padding: 3rem 1rem; color: var(--brown-light);">
        <img
          src="https://images.unsplash.com/photo-1555507036-ab1f4038808a?w=200&q=60"
          alt="Empty cart"
          style="width: 100px; height: 80px; object-fit: cover; border-radius: 10px; margin-bottom: 1rem; opacity: 0.4;"
        />
        <p style="font-size: 0.85rem;">Your cart is empty</p>
      </div>
    `;
    document.getElementById('cartTot').textContent = '$0.00';
    return;
  }

  // Build HTML for each cart item using .map() and template literals
  const itemsHTML = cart.map(item => `
    <div class="c-item">
      <div class="c-item-img">
        <img src="${item.img}" alt="${item.name}" />
      </div>
      <div class="c-item-info">
        <strong>${item.name}</strong>
        <span>${item.cat}</span>
      </div>
      <div class="c-item-right">
        <div class="c-price">$${(item.price * item.qty).toFixed(2)}</div>
        <div class="qty-c">
          <button onclick="updateQty(${item.id}, -1)">−</button>
          <span>${item.qty}</span>
          <button onclick="updateQty(${item.id}, +1)">+</button>
        </div>
      </div>
    </div>
  `).join('');  // .join('') turns the array of strings into one string

  cartListEl.innerHTML = itemsHTML;

  // Calculate and display the total price
  const total = cart.reduce((sum, item) => sum + (item.price * item.qty), 0);
  document.getElementById('cartTot').textContent = '$' + total.toFixed(2);
}

/**
 * toggleCart — opens or closes the cart sidebar.
 * Adds/removes "open" class on both the panel and the overlay.
 */
function toggleCart() {
  document.getElementById('cartSide').classList.toggle('open');
  document.getElementById('cartOvr').classList.toggle('open');
}

/**
 * checkout — simulates placing an order.
 * Clears the cart and shows a confirmation message.
 */
function checkout() {
  if (cart.length === 0) {
    showToast('Your cart is empty!');
    return;
  }

  // Clear the cart array
  cart = [];
  updateCartCount();
  renderCart();
  toggleCart();  // close the sidebar

  showToast("Order placed! We'll bake it fresh for you.");
}


/* ========================================================
   6. PRODUCT CARD HTML BUILDER
   Returns an HTML string for one product card.
   Called by renderProducts() for each product.
======================================================== */

/**
 * buildProductCard — generates the HTML for a single product card.
 *
 * @param {object} product — one item from the products array
 * @returns {string} — HTML string
 */
function buildProductCard(product) {

  // Badge HTML — only shown if the product has a badge value
  const badgeMap = {
    fav:  `<span class="p-badge badge-fav">★ Favourite</span>`,
    new:  `<span class="p-badge badge-new">New</span>`,
    sale: `<span class="p-badge badge-sale">Sale</span>`,
  };

  // Get the badge HTML, or empty string if no badge
  const badgeHTML = product.badge ? badgeMap[product.badge] : '';

  // Build and return the complete card HTML
  return `
    <div class="p-card">
      <div class="p-card-img">
        <img src="${product.img}" alt="${product.name}" loading="lazy" />
        ${badgeHTML}
        <button class="p-wish" onclick="event.stopPropagation(); showToast('Added to wishlist ♡')">♡</button>
      </div>
      <div class="p-body">
        <div class="p-cat">${product.cat}</div>
        <h3 class="p-name">${product.name}</h3>
        <p class="p-desc">${product.desc}</p>
        <div class="p-foot">
          <div class="p-price">$${product.price.toFixed(2)}</div>
          <button class="add-btn" onclick="addToCart(${product.id})" title="Add to cart">
            <svg viewBox="0 0 24 24">
              <line x1="12" y1="5" x2="12" y2="19" />
              <line x1="5"  y1="12" x2="19" y2="12" />
            </svg>
          </button>
        </div>
      </div>
    </div>
  `;
}


/* ========================================================
   7. RENDER PRODUCTS
   Fills in all the product grids on the Home and Menu pages.
======================================================== */

/**
 * renderProducts — populates all product grid containers.
 * Called once on page load from init().
 */
function renderProducts() {

  // ── Home page: featured products only ──
  const featGrid = document.getElementById('featGrid');
  if (featGrid) {
    // Filter to only featured items, build cards, join into one string
    featGrid.innerHTML = products
      .filter(p => p.featured)
      .map(buildProductCard)
      .join('');
  }

  // ── Menu page: all products ──
  const allGrid = document.getElementById('mg-all');
  if (allGrid) {
    allGrid.innerHTML = products.map(buildProductCard).join('');
  }

  // ── Menu page: one grid per category ──
  const categories = ['cakes', 'pastries', 'breads', 'cupcakes'];

  categories.forEach(category => {
    const grid = document.getElementById('mg-' + category);
    if (grid) {
      // Filter products to this category
      const filtered = products.filter(p => p.cat === category);
      grid.innerHTML = filtered.map(buildProductCard).join('');
    }
  });
}


/* ========================================================
   8. RENDER GALLERY
   Builds the masonry photo grid and Instagram grid
   on the Gallery page.
======================================================== */

/**
 * renderGallery — injects gallery items into #galGrid
 * and Instagram images into #igGrid.
 * Filters by category if a filter is provided.
 *
 * @param {string} filter — category to filter by, or 'all'
 */
function renderGallery(filter = 'all') {

  const galGrid = document.getElementById('galGrid');
  if (!galGrid) return;   // safety: exit if the element doesn't exist

  // Either show all items, or only matching category
  const visibleItems = (filter === 'all')
    ? galItems
    : galItems.filter(item => item.cat === filter);

  // Build HTML for each gallery tile
  const tilesHTML = visibleItems.map(item => `
    <div class="g-item" data-cat="${item.cat}">
      <img src="${item.img}" alt="${item.title}" loading="lazy" />
      <div class="g-hover">
        <div class="g-label">
          <h4>${item.title}</h4>
          <span>${item.sub}</span>
        </div>
      </div>
    </div>
  `).join('');

  galGrid.innerHTML = tilesHTML;

  // ── Instagram grid ──
  const igGrid = document.getElementById('igGrid');
  if (igGrid) {
    igGrid.innerHTML = igImgs.map(url => `
      <div class="insta-cell">
        <img src="${url}" alt="Instagram post" loading="lazy" />
      </div>
    `).join('');
  }
}

/**
 * filterGal — called when a filter button is clicked in the gallery.
 * Updates active state on buttons and re-renders the gallery.
 *
 * @param {string} category — category to filter by
 * @param {HTMLElement} clickedBtn — the button that was clicked
 */
function filterGal(category, clickedBtn) {
  // Remove active class from all filter buttons
  document.querySelectorAll('.gal-filter .tab-btn').forEach(btn => {
    btn.classList.remove('active');
  });

  // Add active class to the clicked button
  clickedBtn.classList.add('active');

  // Re-render the gallery with the new filter
  renderGallery(category);
}


