/**
 * injectFooter — injects the footer HTML into a given placeholder element.
 * Only injects once (checks if the element is already filled).
 *
 * @param {string} placeholderId — the id of the div to inject into
 */
function injectFooter(placeholderId) {
  const placeholder = document.getElementById(placeholderId);
  // Only inject if the element exists and is currently empty
  if (placeholder && placeholder.innerHTML.trim() === '') {
    placeholder.innerHTML = buildFooterHTML();
  }
}


/* ========================================================
   10. PAGE NAVIGATION
   This is a single-page app — all pages live in one HTML
   file and we show/hide them using CSS (display: none/block).
======================================================== */

// Map each page ID to its footer placeholder ID
const footerPlaceholders = {
  home:    'hfoot',
  menu:    'mfoot',
  about:   'afoot',
  custom:  'cfoot',
  gallery: 'gfoot',
  contact: 'ctfoot',
};

/**
 * showPage — switches the visible page.
 * Hides all pages, shows the target, updates nav links,
 * injects footer if needed, and re-initialises animations.
 *
 * @param {string} pageId — id of the page div to show
 * @returns {boolean} false — prevents default anchor behaviour
 */
function showPage(pageId) {

  // Hide every page by removing "active" class
  document.querySelectorAll('.page').forEach(page => {
    page.classList.remove('active');
  });

  // Show the requested page
  document.getElementById(pageId).classList.add('active');

  // Scroll back to top smoothly
  window.scrollTo({ top: 0, behavior: 'smooth' });

  // Update nav link active states
  document.querySelectorAll('.nav-links a').forEach(link => {
    link.classList.remove('active');
  });

  const activeLink = document.getElementById('nl-' + pageId);
  if (activeLink) {
    activeLink.classList.add('active');
  }

  // Inject the footer for this page (if not already done)
  injectFooter(footerPlaceholders[pageId]);

  // The gallery needs special rendering when we navigate to it
  if (pageId === 'gallery') {
    renderGallery();
  }

  // Re-run fade-up animation observer for the new page content
  // Small delay lets the DOM finish rendering first
  setTimeout(initFadeUpAnimations, 60);

  // Return false prevents the <a href="#"> from jumping the page
  return false;
}


/* ========================================================
   11. MENU TAB SWITCHING
   Shows/hides category sections within the Menu page.
======================================================== */

/**
 * switchTab — shows one menu category and hides the others.
 * Also updates which tab button looks "active".
 *
 * @param {string} category — e.g. 'cakes', 'all', etc.
 * @param {HTMLElement} clickedBtn — the tab button element
 */
function switchTab(category, clickedBtn) {

  // Hide all category sections
  document.querySelectorAll('.m-cat').forEach(section => {
    section.classList.remove('active');
  });

  // Remove active class from all tab buttons
  document.querySelectorAll('.menu-tabs .tab-btn').forEach(btn => {
    btn.classList.remove('active');
  });

  // Show the selected category
  document.getElementById('mc-' + category).classList.add('active');

  // Highlight the clicked button
  clickedBtn.classList.add('active');
}


