/**
 * selOccasion — highlights a selected occasion card
 * on the Custom Orders page and updates the hidden select field.
 *
 * @param {HTMLElement} clickedCard — the card div that was clicked
 * @param {string} occasionName — e.g. 'Birthday', 'Wedding'
 */
function selOccasion(clickedCard, occasionName) {
  // Remove selection highlight from all cards
  document.querySelectorAll('.opt-card').forEach(card => {
    card.classList.remove('sel');
  });

  // Highlight the clicked card
  clickedCard.classList.add('sel');

  // Update the dropdown select to match
  const selectEl = document.getElementById('cf_oc');
  if (selectEl) {
    selectEl.value = occasionName;
  }
}

/**
 * submitCustom — handles the Custom Order form submission.
 * Validates required fields, shows a toast, and clears the form.
 */
function submitCustom() {
  const firstName = document.getElementById('cf_fn').value.trim();
  const email     = document.getElementById('cf_em').value.trim();

  // Basic validation — check required fields are filled in
  if (!firstName || !email) {
    showToast('Please fill in your name and email.');
    return;
  }

  // Success message
  showToast("Order request sent! We'll be in touch within 24 hours.");

  // Clear all text inputs and textareas within the custom page
  document.querySelectorAll('#custom input, #custom textarea').forEach(field => {
    field.value = '';
  });

  // Deselect all flavour chips
  document.querySelectorAll('.flv').forEach(chip => {
    chip.classList.remove('sel');
  });

  // Deselect all occasion cards
  document.querySelectorAll('.opt-card').forEach(card => {
    card.classList.remove('sel');
  });
}

/**
 * submitContact — handles the Contact page form submission.
 * Validates required fields and clears the form on success.
 */
function submitContact() {
  const name    = document.getElementById('ctf_n').value.trim();
  const email   = document.getElementById('ctf_e').value.trim();
  const message = document.getElementById('ctf_m').value.trim();

  // All three fields are required
  if (!name || !email || !message) {
    showToast('Please fill in all required fields.');
    return;
  }

  // Success
  showToast("Message sent! We'll reply within one business day.");

  // Clear the form fields
  document.getElementById('ctf_n').value = '';
  document.getElementById('ctf_e').value = '';
  document.getElementById('ctf_m').value = '';
}

/**
 * subNewsletter — handles the newsletter sign-up on the Home page.
 */
function subNewsletter() {
  const emailInput = document.getElementById('nlEmail');
  const email = emailInput.value.trim();

  if (!email) {
    showToast('Please enter your email address.');
    return;
  }

  showToast('Subscribed! Welcome to the Le Petit Four family.');
  emailInput.value = '';
}


/* ========================================================
   14. TOAST NOTIFICATION
   A small popup message that appears briefly at the bottom
   of the screen, then fades out automatically.
======================================================== */

// We store the timeout ID so we can clear it if a new toast
// comes in before the previous one has hidden itself.
let toastTimeout;

/**
 * showToast — displays a temporary notification message.
 *
 * @param {string} message — the text to display
 */
function showToast(message) {
  const toastEl   = document.getElementById('toast');
  const toastMsgEl = document.getElementById('toastMsg');

  // Set the message text
  toastMsgEl.textContent = message;

  // Add "show" class to trigger the CSS animation (slides up)
  toastEl.classList.add('show');

  // Clear any previous countdown
  clearTimeout(toastTimeout);

  // Automatically hide after 3.2 seconds
  toastTimeout = setTimeout(() => {
    toastEl.classList.remove('show');
  }, 3200);
}


