/**
 * toggleMob — opens or closes the mobile dropdown menu.
 * Toggles the "open" class which is handled by CSS.
 */
function toggleMob() {
  document.getElementById('mobMenu').classList.toggle('open');
}


/* ========================================================
   16. NAVBAR SCROLL SHRINK
   When the user scrolls down more than 40px, we add the
   "scrolled" class to the nav, which shrinks its height
   via CSS transition.
======================================================== */
window.addEventListener('scroll', function () {
  const nav = document.getElementById('nav');
  // classList.toggle with a boolean adds/removes the class based on condition
  nav.classList.toggle('scrolled', window.scrollY > 40);
});


/* ========================================================
   17. SCROLL FADE-UP ANIMATION
   Uses the IntersectionObserver API to detect when elements
   with class "fu" (fade up) enter the visible area.
   When they do, we add class "vis" which triggers the CSS
   transition defined in style.css.
======================================================== */

/**
 * initFadeUpAnimations — sets up the scroll observer.
 * Called once on page load and again whenever we switch pages.
 */
function initFadeUpAnimations() {

  // Create an observer that fires when elements become visible
  const observer = new IntersectionObserver(function (entries) {
    entries.forEach(function (entry) {
      if (entry.isIntersecting) {
        // Element has entered the viewport — make it visible
        entry.target.classList.add('vis');
        // Stop observing this element once it's been revealed
        observer.unobserve(entry.target);
      }
    });
  }, {
    threshold: 0.12,   // fires when 12% of the element is visible
  });

  // Find all fade-up elements that haven't been revealed yet
  document.querySelectorAll('.fu:not(.vis)').forEach(function (el) {
    observer.observe(el);
  });
}


/* ========================================================
   18. INITIALISATION
   This runs once when the page has fully loaded.
   Sets up the initial state.
======================================================== */
document.addEventListener('DOMContentLoaded', function () {

  // Render product grids on Home and Menu pages
  renderProducts();

  // Render the empty cart UI
  renderCart();

  // Inject the footer for the home page (which is shown first)
  injectFooter('hfoot');

  // Start the scroll animations for any elements already visible
  setTimeout(initFadeUpAnimations, 100);

  console.log('Le Petit Four bakery site loaded successfully!');
});